   106→	query := &datasources.GetDataSourceQuery{UID: datasourceUID, OrgID: user.GetOrgID()}
   107→	ss := SqlStore{db: dc.SQLStore, logger: dc.logger}
   108→	ds, err := ss.GetDataSource(ctx, query)
   109→	if err != nil {
