   113→	dc.CacheService.Set(uidCacheKey, ds, dc.cacheTTL)
   114→	dc.CacheService.Set(idKey(ds.ID), ds, dc.cacheTTL)
   115→
   116→	if err = dc.canQuery(user, ds); err != nil {
   117→		return nil, err
   118→	}
   119→
   120→	return ds, nil
   121→}
